// Validate and prepare input
const body = $input.first().json.body;

const required = ['room_type', 'occasion', 'existing_colors', 'furniture_style'];
for (const field of required) {
  if (!body[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

const existingColors = Array.isArray(body.existing_colors)
  ? body.existing_colors.join(', ')
  : body.existing_colors;

return {
  room_type: body.room_type,
  occasion: body.occasion,
  existing_colors: existingColors,
  furniture_style: body.furniture_style,
  budget: body.budget || 'mid-range',
  user_id: body.user_id || 'anonymous',
  timestamp: new Date().toISOString()
};

