// Parse GPT-4 response
const rawContent = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '';

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  // Try extracting JSON from response if wrapped in markdown
  const match = rawContent.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse GPT-4 response as JSON');
  }
}

return {
  ...parsed,
  raw_gpt_response: rawContent,
  input_data: {
    room_type: $('Validate & Prepare Input').first().json.room_type,
    occasion: $('Validate & Prepare Input').first().json.occasion,
    existing_colors: $('Validate & Prepare Input').first().json.existing_colors,
    furniture_style: $('Validate & Prepare Input').first().json.furniture_style,
    budget: $('Validate & Prepare Input').first().json.budget,
    user_id: $('Validate & Prepare Input').first().json.user_id,
    timestamp: $('Validate & Prepare Input').first().json.timestamp
  }
};

// Merge DALL-E image URL with recommendation data
const recommendation = $('Parse GPT-4 Response').first().json;
const dalleResponse = $input.first().json;

const imageUrl = dalleResponse.data?.[0]?.url || dalleResponse.url || 'Image generation failed';

return {
  ...recommendation,
  room_visualization_url: imageUrl
};

